import { ChipAtom } from '../../../tooltip-atoms/components/ChipAtom.js';
import { SecondaryAtom } from '../../../tooltip-atoms/components/SecondaryAtom.js';
import type { TooltipValueProps } from '../../types/tooltip.js';

export const TooltipValueContent = (props: TooltipValueProps) => {
  const { children, variant = 'secondary', className, ...rest } = props;

  return (
    <div {...rest}>
      {variant === 'chip' ? (
        <ChipAtom className={className}>{children}</ChipAtom>
      ) : (
        <SecondaryAtom>{children}</SecondaryAtom>
      )}
    </div>
  );
};

TooltipValueContent['displayName'] = 'TooltipValueContent';
